const CATS = ["All","Dals & Pulses","Flour","Rice","Millets","Pickles","Podis","Herbal & Wellness"];
const CAT_EMOJI = {"All":"✦","Dals & Pulses":"🫘","Flour":"🌾","Rice":"🍚","Millets":"🌿","Pickles":"🫙","Podis":"🌶️","Herbal & Wellness":"🌱"};
const WHATSAPP = "15178997699";
const FREE_THRESHOLD = 40;

export default function App() {
  const [cat, setCat]         = useState("All");
  const [q, setQ]             = useState("");
  const [searchOpen, setSearchOpen] = useState(false);
  const [onlyStock, setOnlyStock]   = useState(false);
  const [onlyOrganic, setOnlyOrganic] = useState(false);
  const [cart, setCart]       = useState({});
  const [notify, setNotify]   = useState({});
  const [cartOpen, setCartOpen] = useState(false);
  const [mode, setMode]       = useState("delivery");
  const [placed, setPlaced]   = useState(false);
  const [lightbox, setLightbox] = useState(null); // { src, name }

  const filtered = useMemo(()=> PRODUCTS.filter(p => {
    const okCat = cat==="All" || p.cat===cat;
    const okQ   = !q || (p.name+p.brand).toLowerCase().includes(q.toLowerCase());
    const okS   = !onlyStock || p.stock;
    const okO   = !onlyOrganic || p.organic;
    return okCat && okQ && okS && okO;
  }),[cat,q,onlyStock,onlyOrganic]);

  const add = id => setCart(c=>({...c,[id]:(c[id]||0)+1}));
  const dec = id => setCart(c=>{ const n=(c[id]||0)-1; const x={...c}; n<=0?delete x[id]:x[id]=n; return x; });
  const toggleNotify = id => setNotify(n=>({...n,[id]:!n[id]}));

  const cartItems = Object.entries(cart).map(([id,qty])=>({...PRODUCTS.find(p=>p.id===+id),qty}));
  const count     = cartItems.reduce((s,i)=>s+i.qty,0);
  const subtotal  = cartItems.reduce((s,i)=>s+(i.price*i.qty),0);
  const delivery  = mode==="pickup"||subtotal>=FREE_THRESHOLD ? 0 : 4.99;
  const total     = subtotal+delivery;

  const orderWA = () => {
    const lines = cartItems.map(i=>`• ${i.qty}× ${i.name} (${i.weight}) — $${(i.price*i.qty).toFixed(2)}`).join("%0a");
    const msg = `*Order — Exotik-Desi*%0a${lines}%0a%0a${mode==="pickup"?"Pickup: Monmouth Junction":"Home delivery"}%0aSubtotal: $${subtotal.toFixed(2)}%0aDelivery: $${delivery.toFixed(2)}%0a*Total: $${total.toFixed(2)}*`;
    window.open(`https://wa.me/${WHATSAPP}?text=${msg}`,"_blank");
    setPlaced(true);
  };

  return (
    <div style={{maxWidth:430,margin:"0 auto",minHeight:"100vh",background:"#FFFBF4",fontFamily:"DM Sans, system-ui, sans-serif",fontSize:14,display:"flex",flexDirection:"column"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@600;700&family=DM+Sans:wght@400;500;600;700&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;}
        button{font-family:inherit;cursor:pointer;border:none;}
        input{font-family:inherit;}
        ::-webkit-scrollbar{display:none;}
        .pcard{transition:transform .15s,box-shadow .15s;}
        .pcard:hover{transform:translateY(-2px);box-shadow:0 8px 24px rgba(232,98,26,.15);}
        @keyframes blink{0%,100%{opacity:1}50%{opacity:.25}}
        @keyframes fadeup{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}
      `}</style>

      {/* ── DEMO BANNER ── */}
      <div style={{background:"#FEF3C7",padding:"7px 16px",display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
        <div style={{width:7,height:7,borderRadius:999,background:"#D97706",animation:"blink 1.4s infinite"}}/>
        <span style={{fontSize:11,fontWeight:700,color:"#92400E",letterSpacing:.6,textTransform:"uppercase"}}>Demo Preview — Built for Exotik-Desi</span>
      </div>

      {/* ── HEADER ── */}
      <div style={{background:"#1A1208",padding:"16px 18px 12px",position:"sticky",top:0,zIndex:30}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
          <div>
            <div style={{fontFamily:"Playfair Display, serif",fontWeight:700,fontSize:22,color:"#F5C842",letterSpacing:-.3,lineHeight:1}}>Exotik-Desi</div>
            <div style={{fontSize:10,color:"#9C7C3C",letterSpacing:2.5,textTransform:"uppercase",marginTop:3}}>Monmouth Junction · NJ</div>
          </div>
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            <button onClick={()=>setSearchOpen(s=>!s)} style={{width:38,height:38,borderRadius:10,background:"#2C2010",display:"grid",placeItems:"center",color:"#D4A017"}}>
              <Search size={17}/>
            </button>
            <button onClick={()=>setCartOpen(true)} style={{height:38,borderRadius:10,background:"#E8621A",color:"#fff",padding:"0 14px",fontWeight:700,display:"flex",alignItems:"center",gap:6,position:"relative",fontSize:13}}>
              <ShoppingCart size={16}/>
              <span>{count>0?count:"Cart"}</span>
              {count>0&&<span style={{position:"absolute",top:-6,right:-6,background:"#F5C842",color:"#1A1208",borderRadius:999,fontSize:9,fontWeight:800,minWidth:17,height:17,display:"grid",placeItems:"center"}}>{count}</span>}
            </button>
          </div>
        </div>

        {/* Search */}
        {searchOpen&&(
          <div style={{display:"flex",gap:8,alignItems:"center",background:"#2C2010",borderRadius:10,padding:"8px 12px",marginBottom:8,animation:"fadeup .15s ease"}}>
            <Search size={14} color="#9C7C3C"/>
            <input autoFocus value={q} onChange={e=>setQ(e.target.value)}
              placeholder="Search dal, rice, ashwagandha…"
              style={{flex:1,background:"transparent",border:"none",outline:"none",color:"#FDF6E9",fontSize:13}}/>
            {q&&<button onClick={()=>setQ("")} style={{background:"none",color:"#9C7C3C",padding:0}}><X size={13}/></button>}
          </div>
        )}

        {/* Category pills */}
        <div style={{display:"flex",gap:6,overflowX:"auto",flexWrap:"nowrap",paddingBottom:2}}>
          {CATS.map(c=>(
            <button key={c} onClick={()=>setCat(c)} style={{
              flexShrink:0,padding:"6px 14px",borderRadius:999,fontSize:12,fontWeight:600,whiteSpace:"nowrap",
              background:cat===c?"#E8621A":"#2C2010",
              color:cat===c?"#fff":"#9C7C3C",
              border:"1px solid",borderColor:cat===c?"#E8621A":"#3D2E18",
              transition:"all .15s",
            }}>{CAT_EMOJI[c]} {c}</button>
          ))}
        </div>
      </div>

      {/* ── DELIVERY STRIP ── */}
      <div style={{background:"#FDF1E0",borderBottom:"1px solid #F0E0C0",padding:"9px 18px",display:"flex",alignItems:"center",gap:8}}>
        <Truck size={14} color="#E8621A"/>
        <span style={{fontSize:12,color:"#7C4A1A"}}>Free delivery over <b style={{color:"#E8621A"}}>${FREE_THRESHOLD}</b> · Pickup at Monmouth Junction · <span style={{color:"#E8621A",fontWeight:600}}>WhatsApp orders</span></span>
      </div>

      {/* ── FILTERS ── */}
      <div style={{padding:"10px 14px 6px",display:"flex",gap:8,alignItems:"center"}}>
        {[[onlyStock,setOnlyStock,"✓ In Stock"],[onlyOrganic,setOnlyOrganic,"🌱 Organic"]].map(([on,set,label])=>(
          <button key={label} onClick={()=>set(v=>!v)} style={{
            padding:"5px 12px",borderRadius:999,fontSize:12,fontWeight:600,
            background:on?"#14532d":"#FDF1E0",
            color:on?"#fff":"#7C4A1A",
            border:"1px solid",borderColor:on?"#14532d":"#E8D5B0",
            transition:"all .15s",
          }}>{label}</button>
        ))}
        <span style={{marginLeft:"auto",fontSize:11,color:"#B08050",fontWeight:500}}>{filtered.length} items</span>
      </div>

      {/* ── PRODUCT GRID ── */}
      <div style={{flex:1,padding:"4px 12px 100px",display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
        {filtered.map(p => {
          const inCart = cart[p.id]||0;
          const noted  = notify[p.id];
          const imgKey = IMG_MAP[p.id];
          const imgSrc = imgKey ? IMGS[imgKey] : null;

          return (
            <div key={p.id} className="pcard" style={{
              background:"#fff",
              border:"1px solid #F0E0C0",
              borderRadius:16,
              overflow:"hidden",
              display:"flex",flexDirection:"column",
              boxShadow:"0 2px 8px rgba(232,98,26,.06)",
            }}>
              {/* Image area — tap to zoom */}
              <div
                onClick={()=>imgSrc&&setLightbox({src:imgSrc,name:p.name})}
                style={{
                  width:"100%",height:120,
                  background: imgSrc ? "#FFFBF4" : "linear-gradient(135deg,#FDF1E0,#F5E8D0)",
                  display:"flex",alignItems:"center",justifyContent:"center",
                  position:"relative",overflow:"hidden",
                  cursor: imgSrc?"zoom-in":"default",
                }}>
                {imgSrc
                  ? <>
                      <img src={imgSrc} alt={p.name} style={{width:"100%",height:"100%",objectFit:"contain",padding:8}}/>
                      <div style={{position:"absolute",bottom:6,right:6,background:"rgba(26,18,8,.55)",borderRadius:6,padding:"3px 6px",display:"flex",alignItems:"center",gap:3}}>
                        <span style={{fontSize:9,color:"#F5C842",fontWeight:700}}>TAP TO ZOOM</span>
                      </div>
                    </>
                  : <span style={{fontSize:32}}>{CAT_EMOJI[p.cat]||"🛒"}</span>
                }
                {/* Organic badge */}
                {p.organic&&(
                  <div style={{position:"absolute",top:7,right:7,background:"#14532d",borderRadius:999,padding:"2px 7px",display:"flex",alignItems:"center",gap:3}}>
                    <Leaf size={9} color="#86efac"/>
                    <span style={{fontSize:9,fontWeight:700,color:"#86efac"}}>ORGANIC</span>
                  </div>
                )}
                {/* Coming soon overlay */}
                {!p.stock&&(
                  <div style={{position:"absolute",inset:0,background:"rgba(26,18,8,.55)",display:"flex",alignItems:"center",justifyContent:"center"}}>
                    <span style={{fontSize:11,fontWeight:700,color:"#F5C842",letterSpacing:1,textTransform:"uppercase"}}>Coming Soon</span>
                  </div>
                )}
              </div>

              {/* Info */}
              <div style={{padding:"10px 11px 11px",flex:1,display:"flex",flexDirection:"column",gap:4}}>
                <div style={{fontSize:10,color:"#B08050",fontWeight:600,letterSpacing:.3}}>{p.brand}</div>
                <div style={{fontFamily:"Playfair Display, serif",fontWeight:600,fontSize:14,lineHeight:1.25,color:"#1A1208",flex:1}}>
                  {p.name}
                </div>
                <div style={{fontSize:11,color:"#C0A07A"}}>{p.weight}</div>

                <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginTop:6}}>
                  <div style={{fontFamily:"Playfair Display, serif",fontWeight:700,fontSize:18,color:p.price==null?"#C0A07A":"#1A1208"}}>
                    {p.price!=null?`$${p.price.toFixed(2)}`:"—"}
                  </div>

                  {p.stock ? (
                    inCart>0 ? (
                      <div style={{display:"flex",alignItems:"center",gap:5,background:"#1A1208",borderRadius:9,padding:"4px 6px"}}>
                        <button onClick={()=>dec(p.id)} style={{background:"transparent",color:"#F5C842",display:"grid",placeItems:"center",padding:2}}><Minus size={13}/></button>
                        <span style={{color:"#fff",fontWeight:700,fontSize:13,minWidth:14,textAlign:"center"}}>{inCart}</span>
                        <button onClick={()=>add(p.id)} style={{background:"transparent",color:"#F5C842",display:"grid",placeItems:"center",padding:2}}><Plus size={13}/></button>
                      </div>
                    ):(
                      <button onClick={()=>add(p.id)} style={{
                        background:"#E8621A",color:"#fff",borderRadius:9,
                        padding:"7px 12px",fontWeight:700,fontSize:12,
                        display:"flex",alignItems:"center",gap:4,
                      }}><Plus size={12}/> Add</button>
                    )
                  ):(
                    <button onClick={()=>toggleNotify(p.id)} style={{
                      background:noted?"#F0FDF4":"#FFFBF4",
                      color:noted?"#166534":"#B08050",
                      border:"1px solid",borderColor:noted?"#86efac":"#E8D5B0",
                      borderRadius:9,padding:"6px 9px",fontWeight:600,fontSize:11,
                      display:"flex",alignItems:"center",gap:4,
                    }}>
                      {noted?<><Check size={11}/> Noted</>:<><Bell size={11}/> Notify</>}
                    </button>
                  )}
                </div>
              </div>
            </div>
          );
        })}

        {filtered.length===0&&(
          <div style={{gridColumn:"1/-1",textAlign:"center",padding:"50px 0",color:"#C0A07A"}}>
            Nothing found for "<b>{q}</b>"
          </div>
        )}
      </div>

      {/* ── LIGHTBOX ── */}
      {lightbox&&(
        <div
          onClick={()=>setLightbox(null)}
          style={{
            position:"fixed",inset:0,zIndex:100,
            background:"rgba(26,18,8,.92)",
            display:"flex",flexDirection:"column",
            alignItems:"center",justifyContent:"center",
            padding:20,
          }}>
          {/* Close button */}
          <button
            onClick={()=>setLightbox(null)}
            style={{
              position:"absolute",top:16,right:16,
              background:"rgba(255,255,255,.12)",
              border:"none",borderRadius:999,
              width:40,height:40,display:"grid",placeItems:"center",
              color:"#fff",cursor:"pointer",
            }}>
            <X size={20}/>
          </button>

          {/* Image */}
          <div style={{
            width:"100%",maxWidth:380,
            background:"#FFFBF4",
            borderRadius:20,overflow:"hidden",
            boxShadow:"0 24px 80px rgba(0,0,0,.5)",
            animation:"fadeup .2s ease",
          }}>
            <img
              src={lightbox.src}
              alt={lightbox.name}
              style={{width:"100%",objectFit:"contain",maxHeight:"60vh",padding:16,background:"#FFFBF4"}}
            />
            <div style={{
              padding:"14px 18px",
              background:"#1A1208",
              borderTop:"1px solid #3D2E18",
            }}>
              <div style={{fontFamily:"Playfair Display, serif",fontWeight:700,fontSize:18,color:"#F5C842"}}>
                {lightbox.name}
              </div>
              <div style={{fontSize:12,color:"#9C7C3C",marginTop:4}}>Tap anywhere to close</div>
            </div>
          </div>
        </div>
      )}

      {/* ── CART DRAWER ── */}
      {cartOpen&&(
        <div onClick={()=>setCartOpen(false)} style={{position:"fixed",inset:0,background:"rgba(26,18,8,.6)",zIndex:50,display:"flex",flexDirection:"column",justifyContent:"flex-end"}}>
          <div onClick={e=>e.stopPropagation()} style={{
            background:"#FFFBF4",borderRadius:"20px 20px 0 0",
            maxHeight:"88vh",display:"flex",flexDirection:"column",
            boxShadow:"0 -8px 40px rgba(26,18,8,.3)"
          }}>
            {/* Handle */}
            <div style={{display:"flex",justifyContent:"center",padding:"12px 0 4px"}}>
              <div style={{width:36,height:4,borderRadius:2,background:"#E8D5B0"}}/>
            </div>

            {/* Header */}
            <div style={{padding:"8px 18px 12px",display:"flex",justifyContent:"space-between",alignItems:"center",borderBottom:"1px solid #F0E0C0"}}>
              <div style={{fontFamily:"Playfair Display, serif",fontWeight:700,fontSize:20,color:"#1A1208"}}>
                Your basket {count>0&&<span style={{fontSize:13,color:"#B08050",fontFamily:"DM Sans, sans-serif",fontWeight:400}}>({count})</span>}
              </div>
              <button onClick={()=>setCartOpen(false)} style={{background:"none",color:"#B08050",padding:4}}><X size={20}/></button>
            </div>

            {/* Items */}
            <div style={{overflowY:"auto",padding:"12px 18px",flex:1}}>
              {cartItems.length===0&&(
                <div style={{textAlign:"center",color:"#C0A07A",padding:"30px 0",fontSize:13}}>
                  Your basket is empty.<br/>Add something delicious!
                </div>
              )}
              {cartItems.map(i=>(
                <div key={i.id} style={{display:"flex",alignItems:"center",gap:12,padding:"11px 0",borderBottom:"1px solid #F5EDD8"}}>
                  {IMG_MAP[i.id]&&IMGS[IMG_MAP[i.id]]&&(
                    <img src={IMGS[IMG_MAP[i.id]]} alt={i.name} style={{width:44,height:44,objectFit:"contain",borderRadius:8,background:"#FDF1E0",padding:4,flexShrink:0}}/>
                  )}
                  <div style={{flex:1}}>
                    <div style={{fontWeight:600,fontSize:13,color:"#1A1208"}}>{i.name}</div>
                    <div style={{fontSize:12,color:"#B08050"}}>{i.weight} · ${i.price.toFixed(2)} each</div>
                  </div>
                  <div style={{display:"flex",alignItems:"center",gap:7}}>
                    <button onClick={()=>dec(i.id)} style={{width:26,height:26,borderRadius:7,border:"1px solid #F0E0C0",background:"#fff",display:"grid",placeItems:"center"}}><Minus size={12}/></button>
                    <span style={{fontWeight:700,minWidth:16,textAlign:"center",color:"#1A1208"}}>{i.qty}</span>
                    <button onClick={()=>add(i.id)} style={{width:26,height:26,borderRadius:7,border:"1px solid #F0E0C0",background:"#fff",display:"grid",placeItems:"center"}}><Plus size={12}/></button>
                  </div>
                  <div style={{fontWeight:700,fontSize:13,minWidth:40,textAlign:"right",color:"#E8621A"}}>${(i.price*i.qty).toFixed(2)}</div>
                </div>
              ))}
            </div>

            {/* Checkout */}
            {cartItems.length>0&&(
              <div style={{padding:"14px 18px",borderTop:"1px solid #F0E0C0",background:"#fff"}}>
                {/* Toggle */}
                <div style={{display:"flex",gap:8,marginBottom:12}}>
                  {[["delivery","Home Delivery",Truck],["pickup","Pickup",Store]].map(([m,label,Icon])=>(
                    <button key={m} onClick={()=>setMode(m)} style={{
                      flex:1,padding:"9px",borderRadius:10,
                      border:"1.5px solid",borderColor:mode===m?"#E8621A":"#F0E0C0",
                      background:mode===m?"#FFF5F0":"#fff",
                      color:mode===m?"#E8621A":"#B08050",
                      fontWeight:700,fontSize:12,display:"flex",alignItems:"center",justifyContent:"center",gap:5,
                    }}>
                      <Icon size={13}/> {label}
                    </button>
                  ))}
                </div>

                {mode==="delivery"&&subtotal<FREE_THRESHOLD&&(
                  <div style={{background:"#FEF9C3",borderRadius:8,padding:"8px 12px",fontSize:12,color:"#92400E",marginBottom:10}}>
                    Add <b>${(FREE_THRESHOLD-subtotal).toFixed(2)}</b> more for free delivery!
                  </div>
                )}

                {[["Subtotal",`$${subtotal.toFixed(2)}`],[`Delivery${delivery===0?" (free)":""}`,delivery===0?"$0.00":`$${delivery.toFixed(2)}`]].map(([l,v])=>(
                  <div key={l} style={{display:"flex",justifyContent:"space-between",fontSize:13,color:"#7C4A1A",marginBottom:5}}>
                    <span>{l}</span><span>{v}</span>
                  </div>
                ))}
                <div style={{display:"flex",justifyContent:"space-between",fontFamily:"Playfair Display, serif",fontWeight:700,fontSize:20,color:"#1A1208",margin:"10px 0 14px"}}>
                  <span>Total</span><span style={{color:"#E8621A"}}>${total.toFixed(2)}</span>
                </div>

                <button onClick={orderWA} style={{
                  width:"100%",background:"#16a34a",color:"#fff",borderRadius:12,
                  padding:"14px",fontWeight:700,fontSize:14,display:"flex",alignItems:"center",justifyContent:"center",gap:8,
                }}>
                  <MessageCircle size={18}/> Order on WhatsApp
                </button>
                {placed&&<div style={{marginTop:8,fontSize:11,color:"#166534",textAlign:"center"}}>✓ Opened in WhatsApp — just hit Send!</div>}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
